class Solution {
public:
    Solution(int m, int n) : m(m), n(n), total(m * n) {
        matrix.resize(m, vector<int>(n, 0));
    }

    vector<int> flip() {
        int idx = rand() % total;
        total--;
        for (int i = 0; i < m; i++) {
            if (idx < n) {
                if (matrix[i][idx] == 0) {
                    matrix[i][idx] = 1;
                    return {i, idx};
                }
                idx++;
            } else {
                idx -= n;
            }
        }
        return {};
    }

    void reset() {
        total = m * n;
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                matrix[i][j] = 0;
            }
        }
    }
private:
    int m, n, total;
    vector<vector<int>> matrix;
};
```
